import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import './EmailVerifyResult.css';

/**
 * EmailVerifyResult
 *
 * This page is the landing destination after the backend server validates a
 * magic-link token and redirects with query params:
 *
 *   /verify-email-result?verified=true&verifiedEmail=...&returnPath=...
 *   /verify-email-result?verified=false&reason=invalid|expired|used
 *
 * On success it auto-redirects to the original review page (via returnPath)
 * and stores the verified email in sessionStorage so the ReviewRating
 * component can pick it up and open the form automatically.
 *
 * On failure it shows an error message with a "Go Back" option.
 */
export default function EmailVerifyResult() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [countdown, setCountdown] = useState(4);

  const verified = searchParams.get('verified') === 'true';
  const verifiedEmail = searchParams.get('verifiedEmail') || '';
  const reason = searchParams.get('reason') || 'invalid';

  // The backend encodes the original page path (e.g. /some-company-slug) into
  // the redirect URL so we can send the user back there.
  // The backend builds: FRONTEND_URL + returnUrl + ?verified=true&verifiedEmail=...
  // We need to reconstruct that original path from the current location.
  // Since the backend redirected to /verify-email-result, the returnUrl is lost
  // unless we store it before leaving. We use sessionStorage for that.
  const savedReturnPath = sessionStorage.getItem('reviewReturnPath') || '/';

  useEffect(() => {
    if (!verified) return;

    // Persist verified email so ReviewRating can read it on the review page
    sessionStorage.setItem('verifiedEmail', verifiedEmail);
    sessionStorage.setItem('emailVerified', 'true');
    // Clean up the return path storage
    sessionStorage.removeItem('reviewReturnPath');

    // Count down then redirect
    const timer = setInterval(() => {
      setCountdown((c) => {
        if (c <= 1) {
          clearInterval(timer);
          // Navigate back to the original review page with flag to open form
          const returnPath = savedReturnPath.startsWith('/')
            ? savedReturnPath
            : `/${savedReturnPath}`;
          navigate(returnPath, { state: { openReviewForm: true, verifiedEmail } });
        }
        return c - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [verified, verifiedEmail, navigate, savedReturnPath]);

  const handleGoBack = () => {
    navigate(savedReturnPath.startsWith('/') ? savedReturnPath : `/${savedReturnPath}`);
  };

  const handleGoHome = () => navigate('/');

  /* ── Failure state ── */
  if (!verified) {
    const reasonMessages = {
      expired: {
        icon: '⏱',
        heading: 'Link Expired',
        body: 'This verification link has expired. Magic links are valid for 30 minutes.',
        action: 'Please go back and request a new verification email.',
      },
      used: {
        icon: '🔒',
        heading: 'Link Already Used',
        body: 'This verification link has already been used.',
        action: 'Each link is single-use. Please request a new one.',
      },
      invalid: {
        icon: '❌',
        heading: 'Invalid Link',
        body: 'This verification link is invalid or has been tampered with.',
        action: 'Please go back and request a new verification email.',
      },
    };

    const msg = reasonMessages[reason] || reasonMessages.invalid;

    return (
      <div className="evr-page">
        <div className="evr-card evr-card--error">
          <div className="evr-icon">{msg.icon}</div>
          <h1 className="evr-heading evr-heading--error">{msg.heading}</h1>
          <p className="evr-body">{msg.body}</p>
          <p className="evr-action-hint">{msg.action}</p>
          <div className="evr-btn-row">
            <button className="evr-btn evr-btn--primary" onClick={handleGoBack}>
              ← Go Back &amp; Try Again
            </button>
            <button className="evr-btn evr-btn--secondary" onClick={handleGoHome}>
              Home
            </button>
          </div>
        </div>
      </div>
    );
  }

  /* ── Success state ── */
  return (
    <div className="evr-page">
      <div className="evr-card evr-card--success">
        <div className="evr-icon">✅</div>
        <h1 className="evr-heading evr-heading--success">Email Verified!</h1>
        <p className="evr-body">
          Your email address <strong>{verifiedEmail}</strong> has been verified successfully.
        </p>
        <p className="evr-redirect-notice">
          Redirecting you back to the review form in <strong>{countdown}</strong> second{countdown !== 1 ? 's' : ''}…
        </p>
        <div className="evr-progress-bar">
          <div
            className="evr-progress-fill"
            style={{ animationDuration: '4s' }}
          />
        </div>
        <button className="evr-btn evr-btn--primary" onClick={handleGoBack}>
          Open Review Form Now →
        </button>
      </div>
    </div>
  );
}
